3_real_world_example.code:
function fetchPage(endpoint, page = 1, limit = 20, sort = 'desc') {
  console.log(`GET ${endpoint}?page=${page}&limit=${limit}&sort=${sort}`);
}

fetchPage('/api/posts');                 // GET /api/posts?page=1&limit=20&sort=desc
fetchPage('/api/posts', 3);              // GET /api/posts?page=3&limit=20&sort=desc
fetchPage('/api/posts', 2, 50, 'asc');  // GET /api/posts?page=2&limit=50&sort=asc

// Explicitly passing undefined triggers the default
fetchPage('/api/posts', undefined, 10); // GET /api/posts?page=1&limit=10&sort=desc

// Passing 0 does NOT trigger default (0 is a valid value)
fetchPage('/api/posts', 0);             // GET /api/posts?page=0&limit=20&sort=desc

6_edge_case.code:
// Earlier params can be referenced in later defaults
function createRect(width, height = width * 2) {
  return { width, height };
}
console.log(createRect(5));    // { width: 5, height: 10 }
console.log(createRect(5, 8)); // { width: 5, height: 8 }

// Default can even be a function call (evaluated fresh each invocation)
function getTimestamp() { return Date.now(); }
function logEvent(msg, ts = getTimestamp()) {
  console.log(ts, msg);
}
